// using a function keeps the code and variables from being global
closeTask();

function closeTask(){
	// TODO - multilanguage
	new Task_uiAction().uiAction_UpdateTaskAndResponseLog("Abstained", 'abstain', current);

	// Redirect platform to stay on task
	if (typeof spModal == 'undefined' ) {
		// action.setRedirectURL(task);
		action.setRedirectURL(current);
	}
}


